// app/page.tsx
import { revalidateTag } from 'next/cache';
import { getAllProducts, PRODUCTS_CACHE_TAG } from '@/lib/db';

export default async function Page() {
  async function syncCatalog() {
    'use server';

    revalidateTag(PRODUCTS_CACHE_TAG, 'max');
  }

  const products = await getAllProducts();

  return (
    <main className="catalog-shell">
      <header className="catalog-header">
        <div>
          <p className="eyebrow">Operations / Inventory</p>
          <h1>Product catalog</h1>
          <p className="subheading">Browse the latest product data from your connected systems.</p>
        </div>
        <form action={syncCatalog}>
          <button type="submit">Sync latest catalog</button>
        </form>
      </header>

      <section className="catalog-summary" aria-label="Catalog summary">
        <div>
          <span className="summary-label">Products</span>
          <strong>{products.length}</strong>
        </div>
        <div>
          <span className="summary-label">Catalog status</span>
          <strong className="status"><span aria-hidden="true" /> In sync</strong>
        </div>
      </section>

      <section className="catalog-table-wrap" aria-labelledby="catalog-heading">
        <div className="table-heading">
          <div>
            <h2 id="catalog-heading">All products</h2>
            <p>Pricing and inventory records currently available to your team.</p>
          </div>
          <span className="record-count">{products.length} records</span>
        </div>
        <table>
          <thead>
            <tr>
              <th scope="col">Product</th>
              <th scope="col">SKU</th>
              <th scope="col">Price</th>
              <th scope="col">Availability</th>
            </tr>
          </thead>
          <tbody>
            {products.map(product => (
              <tr key={product.id}>
                <td><strong>{product.name}</strong></td>
                <td className="muted">PRD-{String(product.id).padStart(4, '0')}</td>
                <td>${product.price.toLocaleString('en-US')}</td>
                <td><span className="availability"><span aria-hidden="true" /> Available</span></td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>
    </main>
  );
}


